import{_ as a,o as t,c as p,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"鹤形","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/防御类/鹤形.md","filePath":"4.资源分区/6.技艺及称号/防御类/鹤形.md"}'),b={name:"4.资源分区/6.技艺及称号/防御类/鹤形.md"};function o(d,e,l,i,_,c){return t(),p("div",null,[...e[0]||(e[0]=[r("h1",{id:"鹤形",tabindex:"-1"},[n("鹤形 "),r("a",{class:"header-anchor",href:"#鹤形","aria-label":'Permalink to "鹤形"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"灵魂蓝调012")])])],-1),s('<h1 id="鹤形-1" tabindex="-1">鹤形 <a class="header-anchor" href="#鹤形-1" aria-label="Permalink to &quot;鹤形&quot;">​</a></h1><p>鹤形</p><p>仿仙鹤之形而创的一道护身法门。本身并无进攻破敌之能，也因此不为大部分修士所看中。</p><p>本资源需要使用者的闪避防御为所有防御类型中最高的才可购买与使用。</p><p>化鹤形<br> D+1000<br> 人物的闪避防御提升敏捷附加点，这是修行加值。<br> 若人物的基础防御类型为闪避防御，则在三豁免检定上获得感知附加点修行加值。<br> 人物可以迅捷动作消耗1点东方类能量，接着进行一个Dp为【支付能量*3】的鹤形检定，获得检定结果出目的、基于闪避防御的全伤害吸收并减少出目*2点闪避防御。减少的闪避防御、获得的全吸收均持续一轮。<br> 人物每习得一项本资源技能树下的技艺，则本能力可消耗的能量就提升1点。</p><p>技能树</p><p>炼白羽<br> C+1000<br> 人物获得机动性为普通的飞行能力，飞行速度等同人物的移动速度。<br> 人物每习得3项本资源技能树下的技艺，此技艺提供的飞行机动性就提升一级。</p><p>舞风萧<br> C+1000<br> 人物进行鹤形检定时，可额外花费至多4点AP以提升鹤形检定的DP，每额外花费1点AP，此次鹤形检定的DP值就提升3点。<br> 人物根据鹤形检定的成功数获得以下效果：<br> 成功数达到4—人物获得基于闪避防御的【适应】<br> 成功数达到8—人物获得基于闪避防御的【坚韧】</p><p>自飘摇<br> C+1000<br> 人物在进行鹤形检定时，可以额外花费一个移动动作，若如此做，则人物在回合外应对一次攻击时，可以反射动作打断性的进行一次移动。<br> 人物在回合外进行的移动距离提升鹤形检定成功数*5米。</p><p>上九霄<br> C+1000<br> 人物每习得一项本资源技能树下的技艺，人物从【化鹤形】获得的闪避防御就提升【敏捷附加】点，豁免检定就提升【感知附加】点修行加值。</p><p>凝霜翼<br> C+1000<br> 当人物受到攻击后，若这次攻击未命中人物，人物对攻击者的下一次近战攻击获得敏捷属性点速度加值。</p><p>任逍遥<br> C+1000<br> 当人物受到攻击后，若这次攻击未命中人物，人物的下一次移动将具有遁地效果，遁力等同于人物的感知属性点。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',14)])])}const m=a(b,[["render",o]]);export{f as __pageData,m as default};
